class Svg:
    def __init__(self, width: int, height: int, title: str) -> None:
        self.width = width
        self.height = height
        self.parts: list[str] = [
            f'<svg xmlns="http://www.w3.org/2000/svg" width="{width}" height="{height}" viewBox="0 0 {width} {height}">',
            f"<title>{escape(title)}</title>",
            '<rect width="100%" height="100%" fill="#f7faf8"/>',
        ]

    def add(self, value: str) -> None:
        self.parts.append(value)

    def rect(
        self,
        x: int,
        y: int,
        w: int,
        h: int,
        fill: str = "#ffffff",
        stroke: str = "#b7c7c3",
        rx: int = 8,
        width: int = 2,
        dash: bool = False,
    ) -> None:
        dash_attr = ' stroke-dasharray="8 6"' if dash else ""
        self.add(
            f'<rect x="{x}" y="{y}" width="{w}" height="{h}" rx="{rx}" '
            f'fill="{fill}" stroke="{stroke}" stroke-width="{width}"{dash_attr}/>'
        )

    def line(self, x1: int, y1: int, x2: int, y2: int, stroke: str = "#33645d", width: int = 2, dash: bool = False) -> None:
        dash_attr = ' stroke-dasharray="7 6"' if dash else ""
        self.add(
            f'<line x1="{x1}" y1="{y1}" x2="{x2}" y2="{y2}" stroke="{stroke}" stroke-width="{width}"{dash_attr}/>'
        )

    def arrow(self, x1: int, y1: int, x2: int, y2: int, stroke: str = "#33645d", width: int = 2) -> None:
        self.line(x1, y1, x2, y2, stroke, width)
        if x2 >= x1:
            points = f"{x2},{y2} {x2 - 10},{y2 - 6} {x2 - 10},{y2 + 6}"
        else:
            points = f"{x2},{y2} {x2 + 10},{y2 - 6} {x2 + 10},{y2 + 6}"
        self.add(f'<polygon points="{points}" fill="{stroke}"/>')

    def text(self, x: int, y: int, text: str, size: int = 16, fill: str = "#1c2f2b", weight: int | str = 400) -> None:
        self.add(
            f'<text x="{x}" y="{y}" font-family="Inter, Arial, sans-serif" '
            f'font-size="{size}" font-weight="{weight}" letter-spacing="0" fill="{fill}">{escape(text)}</text>'
        )

    def multiline(
        self,
        x: int,
        y: int,
        text: str,
        width_chars: int,
        size: int = 14,
        fill: str = "#24413c",
        line_height: int | None = None,
        weight: int | str = 400,
    ) -> int:
        line_height = line_height or size + 6
        lines = []
        for paragraph in text.split("\n"):
            if not paragraph.strip():
                lines.append("")
                continue
            lines.extend(textwrap.wrap(paragraph, width_chars, break_long_words=False) or [""])
        cursor = y
        for line in lines:
            self.text(x, cursor, line, size=size, fill=fill, weight=weight)
            cursor += line_height
        return cursor

    def pill(self, x: int, y: int, text: str, fill: str = "#e5f2ee", stroke: str = "#31756c", text_fill: str = "#123630") -> None:
        width = max(92, 12 * len(text) + 26)
        self.rect(x, y, width, 30, fill=fill, stroke=stroke, rx=15)
        self.text(x + 14, y + 20, text, size=13, fill=text_fill, weight=700)

    def callout(self, x: int, y: int, number: int, label: str, target_x: int, target_y: int) -> None:
        self.line(x, y, target_x, target_y, stroke="#1f5f56", width=2)
        self.add(f'<circle cx="{x}" cy="{y}" r="16" fill="#1f5f56"/>')
        self.text(x - (7 if number < 10 else 11), y + 5, str(number), size=14, fill="#ffffff", weight=800)
        self.text(x + 24, y + 5, label, size=13, fill="#123630", weight=700)

    def finish(self) -> str:
        self.parts.append("</svg>")
        return "\n".join(self.parts) + "\n"


def header(svg: Svg, title: str, subtitle: str) -> None:
    svg.rect(24, 20, svg.width - 48, 78, fill="#ffffff", stroke="#a9bdb8", rx=10)
    svg.text(48, 55, title, size=25, fill="#132f2a", weight=800)
    svg.text(48, 82, subtitle, size=14, fill="#3d5b55")


def footer(svg: Svg) -> None:
    svg.text(36, svg.height - 24, SOURCE_SUMMARY, size=12, fill="#526963")


