def draw_interactions() -> str:
    svg = Svg(1600, 1100, "SeeLinks facet and tile interactions")
    header(svg, "Facet And Tile Interaction Model", "The original SeeLinks UI is built around highlighting, reducing, ordering, colouring, and collecting visible records.")

    columns = [
        ("Facet header", "Click opens or closes. Pin keeps it open. Drag header reorders facets. Drag facet name to the grid pins it and colours tiles.", 48, "#eef5f2"),
        ("Facet value chip", "Click sets primary highlight. Right-click Adjust adds/removes within the facet. Double-click chooses that value. Drag reorders values or creates grid rollup.", 424, "#eef4fb"),
        ("Tile grid", "Single click selects. Double click opens. Drop facet names for colour legends. Drop facet values for rollup cards.", 800, "#fff7e8"),
        ("Toolbar/history", "Choose highlighted reduces to matches. Choose unhighlighted keeps non-matches. Undo view and history chips restore prior reductions.", 1176, "#f7ecf1"),
    ]
    for title, body, x, fill in columns:
        svg.rect(x, 132, 340, 180, fill=fill, stroke="#9db9b2", rx=14)
        svg.text(x + 24, 168, title, size=19, weight=800)
        svg.multiline(x + 24, 202, body, 34, size=14)

    svg.text(56, 374, "Core gestures", size=20, weight=800)
    gestures = [
        ("Click chip", "highlight matching records; count shows highlighted/total when active", 74, 420, 330, 420),
        ("Right-click chip", "adjust additive highlights within the same facet", 74, 500, 330, 500),
        ("Double-click chip", "choose that value and reduce the current view", 74, 580, 330, 580),
        ("Drag chip", "reorder facet values or drop on grid to create a rollup card", 74, 660, 330, 660),
        ("Drag facet name", "drop on grid to pin facet and apply tile colour legend", 74, 740, 330, 740),
        ("Click tile", "toggle manual selection for collection, print, or manual reduce", 74, 820, 330, 820),
        ("Double-click tile", "open docked detail view with tile strip and tabs", 74, 900, 330, 900),
    ]
    for action, result, x, y, tx, ty in gestures:
        svg.rect(x, y - 24, 204, 42, fill="#ffffff", stroke="#9bb8b2", rx=21)
        svg.text(x + 18, y + 5, action, size=14, weight=800)
        svg.arrow(x + 210, y - 2, tx, ty - 2)
        svg.multiline(tx + 18, ty + 4, result, 42, size=13)

    svg.rect(760, 370, 780, 286, fill="#ffffff", stroke="#9bb8b2", rx=14)
    svg.text(790, 408, "Tile state vocabulary", size=20, weight=800)
    states = [
        ("Selected", "manual selection set; exported, printable, collectable"),
        ("Highlighted", "matches current facet highlight expression"),
        ("Active/Open", "current detail-card item"),
        ("Coloured", "tile background comes from active facet value order"),
        ("Rollup", "facet-value summary card dropped into the grid"),
        ("Missing image", "visible badge for missing Micropedia media"),
    ]
    for i, (label, body) in enumerate(states):
        x = 792 + (i % 2) * 360
        y = 446 + (i // 2) * 62
        svg.pill(x, y, label, fill=["#e4f2ee", "#fff1d1", "#e6eefb", "#fde7ef", "#eee8fb", "#e9f4dd"][i])
        svg.multiline(x + 140, y + 12, body, 25, size=12)

    svg.rect(760, 696, 780, 300, fill="#ffffff", stroke="#9bb8b2", rx=14)
    svg.text(790, 734, "Reduction workflow", size=20, weight=800)
    steps = [
        ("1. Highlight", "Use facet chip click/Adjust or link summary."),
        ("2. Choose", "Keep highlighted or keep unhighlighted."),
        ("3. Record", "Pushes a history entry with label, count, total, and highlight snapshot."),
        ("4. Continue", "Repeat inside the smaller current view."),
        ("5. Undo/reset", "Use history chip, Undo view, or Reset."),
    ]
    for i, (label, body) in enumerate(steps):
        x = 800 + i * 140
        y = 812
        svg.rect(x, y, 118, 72, fill="#eef5f2", stroke="#7da69e", rx=10)
        svg.text(x + 14, y + 26, label, size=13, weight=800)
        svg.multiline(x + 14, y + 48, body, 17, size=10)
        if i < len(steps) - 1:
            svg.arrow(x + 120, y + 36, x + 136, y + 36)

    footer(svg)
    return svg.finish()


